import React, { useRef, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, MeshDistortMaterial, Float, MeshWobbleMaterial, Html } from '@react-three/drei';

const BodyPart = ({ position, name, onClick, color = "#00f3ff" }) => {
  const [hovered, setHover] = useState(false);

  return (
    <group 
      position={position} 
      onClick={(e) => {
        e.stopPropagation();
        onClick(name);
      }}
      onPointerOver={() => setHover(true)}
      onPointerOut={() => setHover(false)}
    >
      <mesh>
        <sphereGeometry args={[0.15, 32, 32]} />
        <meshStandardMaterial 
          color={hovered ? "#ff0055" : color} 
          emissive={hovered ? "#ff0055" : color}
          emissiveIntensity={hovered ? 2 : 0.5}
        />
      </mesh>
      {hovered && (
        <Html position={[0, 0.3, 0]} center>
          <div className="bg-black/80 backdrop-blur-md border border-cyan-500/50 px-3 py-1 rounded-full whitespace-nowrap">
            <span className="text-[10px] font-black uppercase tracking-widest text-cyan-400">{name}</span>
          </div>
        </Html>
      )}
    </group>
  );
};

const HumanoidModel = ({ onSelectPart }) => {
  const group = useRef();

  // Subtle rotation
  useFrame((state) => {
    const t = state.clock.getElapsedTime();
    group.current.rotation.y = Math.sin(t / 4) / 8;
  });

  return (
    <group ref={group}>
      {/* Glassmorphic Torso */}
      <Float speed={2} rotationIntensity={0.5} floatIntensity={1}>
        <mesh position={[0, 0, 0]} scale={[1, 1.5, 0.5]}>
          <boxGeometry args={[1, 1, 1]} />
          <MeshDistortMaterial
            color="#ffffff"
            transparent
            opacity={0.2}
            transmission={0.95}
            thickness={2}
            roughness={0}
            distort={0.3}
            speed={2}
          />
        </mesh>
      </Float>

      {/* Stylized Head */}
      <mesh position={[0, 1.2, 0]}>
        <sphereGeometry args={[0.35, 32, 32]} />
        <MeshWobbleMaterial
          color="#00f3ff"
          transparent
          opacity={0.3}
          factor={0.1}
          speed={1}
        />
      </mesh>

      {/* Limbs (Stylized) */}
      <mesh position={[0.7, -0.2, 0]} scale={[0.2, 1.2, 0.2]}>
        <capsuleGeometry args={[1, 1, 4, 8]} />
        <meshStandardMaterial color="#ffffff" transparent opacity={0.1} />
      </mesh>
      <mesh position={[-0.7, -0.2, 0]} scale={[0.2, 1.2, 0.2]}>
        <capsuleGeometry args={[1, 1, 4, 8]} />
        <meshStandardMaterial color="#ffffff" transparent opacity={0.1} />
      </mesh>

      {/* Hotspots */}
      <BodyPart position={[0, 0.8, 0.3]} name="Chest" onClick={onSelectPart} />
      <BodyPart position={[0, 1.2, 0.3]} name="Head" onClick={onSelectPart} />
      <BodyPart position={[0, -0.2, 0.3]} name="Abdomen" onClick={onSelectPart} />
      <BodyPart position={[0.8, 0.2, 0.2]} name="Arms" onClick={onSelectPart} />
      <BodyPart position={[-0.8, 0.2, 0.2]} name="Arms" onClick={onSelectPart} />
      <BodyPart position={[0.3, -1.2, 0.2]} name="Legs" onClick={onSelectPart} />
      <BodyPart position={[-0.3, -1.2, 0.2]} name="Legs" onClick={onSelectPart} />
    </group>
  );
};

const HumanoidCanvas = ({ onSelectPart }) => {
  return (
    <div className="w-full h-full min-h-[500px] cursor-pointer">
      <Canvas shadows>
        <PerspectiveCamera makeDefault position={[0, 0, 5]} />
        <OrbitControls enableZoom={false} enablePan={false} />

        <ambientLight intensity={0.5} />
        <pointLight position={[10, 10, 10]} intensity={1} color="#00f3ff" />
        <spotLight position={[-10, 10, 10]} angle={0.15} penumbra={1} intensity={1} color="#ff0055" />

        <HumanoidModel onSelectPart={onSelectPart} />

        <gridHelper args={[20, 20, 0x00f3ff, 0x002233]} position={[0, -2, 0]} />
      </Canvas>
    </div>
  );
};

export default HumanoidCanvas;
